<template>
  <div class="products-swiper pt-16 pb-5">
    <div class="title mb-10 px-5 d-flex align-center justify-space-between">
      <h2 class="font-weight-black text-sm-h3" :style="`color: ${titleColor}`">
        {{ title }}
      </h2>
      <router-link
        class="text-black text-subtitle-2"
        :to="{
          name: 'products_category',
          query: {
            title: categories[index].title,
            category: categories[index].route,
          },
        }"
        >Shop All</router-link
      >
    </div>
    <!-- Start Loading -->
    <v-container fluid v-if="!products.length">
      <v-row>
        <v-col class="pt-14" cols="12">
          <v-row>
            <v-col cols="3" v-for="num in 4" :key="num">
              <v-skeleton-loader
                type="image,article,button"
              ></v-skeleton-loader>
            </v-col>
          </v-row>
        </v-col>
      </v-row>
    </v-container>
    <!-- End Loading -->
    <Swiper
      :pagination="{ el: '.swiper-pagination', clickable: true }"
      :modules="modules"
      :slides-per-view="4"
      :space-between="35"
      class="pb-9 px-5"
      :navigation="{ prevIcon: '.swiper-prev', nextIcon: '.swiper-next' }"
      :autoplay="{
        delay: 10000,
        disableOnInteraction: false,
        pauseOnMouseEnter: true,
      }"
      :breakpoints="breakpoints"
    >
      <Swiper-Slide v-for="item in props.products" :key="item.id">
        <v-card elevation="0" class="pb-5 cursor-grab">
          <v-hover v-slot="{ isHovering, props }">
            <div
              class="img-parent position-relative overflow-hidden"
              style="height: 200px"
            >
              <img
                :src="
                  showenItem[item.title]
                    ? showenItem[item.title]
                    : item.thumbnail
                "
                :alt="item.thumbnail"
                class="w-100 cursor-pointer"
                :style="`height: 100%; transition: 0.5s all ease-in-out; scale:${
                  isHovering ? 1.05 : 1
                }`"
                v-bind="props"
              />
              <v-btn
                density="compact"
                width="60"
                height="30"
                variant="outlined"
                rounded="xl"
                class="bg-white position-absolute quick-view-btn opacity-0"
                style="
                  text-transform: none;
                  left: 50%;
                  top: 50%;
                  transform: translate(-50%, -50%);
                  font-size: 12px;
                  transition: 0.2s all ease-in-out;
                "
                @click="openQuickView(item)"
                >Quick View</v-btn
              >
            </div>
          </v-hover>
          <v-card-text class="pl-0 pb-1">
            {{
              `(${item.title}) ${item.description}`.length <= 57
                ? `(${item.title}) ${item.description}`
                : `(${item.title}) ${item.description}`.substring(0, 57) + "..."
            }}
          </v-card-text>
          <v-rating
            v-model="item.rating"
            half-increments
            readonly
            color="yellow-darken-2"
            size="x-small"
            density="compact"
          ></v-rating>
          <v-card-text class="pl-0 pt-0">
            <del>${{ item.price }}</del> From
            <v-chip
              color="red"
              class="font-weight-black text-subtitle-1"
              variant="text"
              >${{
                Math.floor(
                  item.price - (item.price * item.discountPercentage) / 100
                )
              }}</v-chip
            >
          </v-card-text>
          <v-btn-toggle v-model="showenItem[item.title]" mandatory>
            <v-btn
              v-for="(pic, i) in item.images"
              :key="i"
              :value="pic"
              size="x-small"
              rounded="xl"
              :ripple="false"
              class="overflow-hidden"
            >
              <img
                :src="pic"
                alt=""
                width="30"
                height="30"
                style="border-radius: 50%; border: 1px solid rgb(135, 135, 135)"
              />
            </v-btn>
          </v-btn-toggle>
          <div class="mt-5">
            <v-btn
              variant="outlined"
              height="44"
              rounded
              class="d-flex justify-center align-center choose-option"
              @click="
                $router.push({
                  name: 'product_details',
                  query: {
                    productId: item.id,
                    title: categories[index].title,
                    category: categories[index].route,
                  },
                })
              "
              >Choose Options
            </v-btn>
          </div>
        </v-card>
      </Swiper-Slide>
      <div class="swiper-prev"></div>
      <div class="swiper-next"></div>
      <div class="swiper-pagination"></div>
    </Swiper>
  </div>
</template>

<script setup>
// DownBelow Importing Component & Library
import { defineProps, ref, computed } from "vue";
import { Swiper, SwiperSlide } from "swiper/vue";
import { Navigation, Pagination, Autoplay } from "swiper/modules";
import { VSkeletonLoader } from "vuetify/lib/components";
import { productsModule } from "@/stores/Products";
const categories = computed(() => productsModule().categories);
// Config Emitter
import { inject } from "vue";
const emitter = inject("emitter");
// End Config Emitter
// * Variables DownBelow
const props = defineProps({
  products: {
    type: Array,
    required: true,
  },
  title: {
    type: String,
  },
  titleColor: {
    type: String,
  },
  index: {
    type: Number,
    required: true,
  },
});
// BreakPoint
const breakpoints = ref({
  0: {
    slidesPerView: 1,
  },
  580: {
    slidesPerView: 2,
  },
  767: {
    slidesPerView: 3,
  },
  990: {
    slidesPerView: 4,
  },
});
const showenItem = ref({});
const modules = [Navigation, Pagination, Autoplay];
// *Functions downBelow ===<
const openQuickView = (product) => emitter.emit("OpenQuickView", product);
</script>

<style>
.products-swiper .swiper-button-next,
.products-swiper .swiper-button-prev {
  width: 35px;
  height: 35px;
  border: 2px solid rgb(95, 95, 95);
  border-radius: 50%;
  background: white;
  top: 35%;
}
.products-swiper .swiper-button-next svg,
.products-swiper .swiper-button-prev svg {
  width: 15px;
  height: 15px;
  color: rgb(53, 53, 53);
}
.swiper-pagination-bullet {
  width: 10px;
  height: 10px;
}
.img-parent:hover .quick-view-btn {
  opacity: 1 !important;
}
/* Media Queries: */
@media (max-width: 580px) {
  .products-swiper .img-parent {
    height: 300px !important;
  }
  .products-swiper .swiper-button-next,
  .products-swiper .swiper-button-prev {
    top: 50%;
  }
}
</style>
